    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // spot: fetchTicker, fetchTickers
        //
        //     {
        //         "symbol": "btc_usdt",
        //         "ticker": {
        //             "high": "29695.57",
        //             "vol": "6890.2789",
        //             "low": "29110",
        //             "change": "0.58",
        //             "turnover": "202769821.06",
        //             "latest": "29405.98"
        //         },
        //         "timestamp": :1692064274908
        //     }
        //
        // swap: fetchTickers
        //
        //     {
        //         "prePositionFeeRate": "0.000053",
        //         "volume": "2435.459",
        //         "symbol": "BTCUSDT",
        //         "highestPrice": "29446.5",
        //         "lowestPrice": "29362.9",
        //         "openPrice": "29419.5",
        //         "markedPrice": "29385.1",
        //         "turnover": "36345526.2438402",
        //         "lastPrice": "29387.0"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "timestamp");
        Object marketId = this.safeString(ticker, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        Object tickerData = this.safeValue(ticker, "ticker", new java.util.HashMap<String, Object>() {{}});
        market = this.safeMarket(marketId, market);
        Object data = ((Helpers.isTrue((Helpers.GetValue(market, "contract"))))) ? ticker : tickerData;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", LbankCore.this.iso8601(timestamp) );
            put( "high", LbankCore.this.safeString2(data, "high", "highestPrice") );
            put( "low", LbankCore.this.safeString2(data, "low", "lowestPrice") );
            put( "bid", null );
            put( "bidVolume", null );
            put( "ask", null );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", LbankCore.this.safeString(data, "openPrice") );
            put( "close", null );
            put( "last", LbankCore.this.safeString2(data, "latest", "lastPrice") );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", LbankCore.this.safeString(data, "change") );
            put( "average", null );
            put( "baseVolume", LbankCore.this.safeString2(data, "vol", "volume") );
            put( "quoteVolume", LbankCore.this.safeString(data, "turnover") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name lbank#fetchTicker
     * @description fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific market
     * @see https://www.lbank.com/en-US/docs/index.html#query-current-market-data-new
     * @param {string} symbol unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTicker(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                Object responseForSwap = (this.fetchTickers(new java.util.ArrayList<Object>(java.util.Arrays.asList(Helpers.GetValue(market, "symbol"))), parameters)).join();
                return this.safeValue(responseForSwap, Helpers.GetValue(market, "symbol"));
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.spotPublicGetTicker24hr(this.extend(request, parameters))).join();
            //
            //     {
            //         "result": "true",
            //         "data": [
            //             {
            //                 "symbol": "btc_usdt",
            //                 "ticker": {
            //                     "high": "29695.57",
            //                     "vol": "6890.2789",
            //                     "low": "29110",
            //                     "change": "0.58",
            //                     "turnover": "202769821.06",
            //                     "latest": "29405.98"
            //                 },
            //                 "timestamp": :1692064274908
            //             }
            //         ],
            //         "error_code": 0,
            //         "ts": :1692064276872
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object first = this.safeDict(data, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parseTicker(first, market);
        });

    }

