    /**
     * @method
     * @name lbank#withdraw
     * @description make a withdrawal
     * @see https://www.lbank.com/en-US/docs/index.html#withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object fee = this.safeString(parameters, "fee");
            parameters = this.omit(parameters, "fee");
            // The relevant coin network fee can be found by calling fetchDepositWithdrawFees (), note: if no network param is supplied then the default network will be used, this can also be found in fetchDepositWithdrawFees ().
            this.checkRequiredArgument("withdraw", fee, "fee");
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "address", address );
                put( "coin", Helpers.GetValue(currency, "id") );
                put( "amount", amount );
                put( "fee", fee );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "memo", tag);
            }
            Object network = this.safeStringUpper2(parameters, "network", "networkName");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("network", "networkName")));
            Object networks = this.safeValue(this.options, "networks");
            Object networkId = this.safeString(networks, ((String)network), network);
            if (Helpers.isTrue(!Helpers.isEqual(networkId, null)))
            {
                Helpers.addElementToObject(request, "networkName", networkId);
            }
            Object response = (this.spotPrivatePostSupplementWithdraw(this.extend(request, parameters))).join();
            //
            //      {
            //          "result":true,
            //          "data": {
            //              "fee":10.00000000000000000000,
            //              "withdrawId":1900377
            //              },
            //          "error_code":0,
            //          "ts":1648992501414
            //      }
            //
            Object result = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            return new java.util.HashMap<String, Object>() {{
                put( "info", result );
                put( "id", LbankCore.this.safeString(result, "withdrawId") );
            }};
        });

    }

    public Object parseTransactionStatus(Object status, Object type)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "1", "pending" );
                put( "2", "ok" );
                put( "3", "failed" );
                put( "4", "canceled" );
                put( "5", "transfer" );
            }} );
            put( "withdrawal", new java.util.HashMap<String, Object>() {{
                put( "1", "pending" );
                put( "2", "canceled" );
                put( "3", "failed" );
                put( "4", "ok" );
            }} );
        }};
        return this.safeString(this.safeValue(statuses, type, new java.util.HashMap<String, Object>() {{}}), status, status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits (private)
        //
        //      {
        //          "insertTime":1649012310000,
        //          "amount":9.00000000000000000000,
        //          "address":"TYASr5UV6HEcXatwdFQfmLVUqQQQMUxHLS",
        //          "networkName":"trc20",
        //          "txId":"081e4e9351dd0274922168da5f2d14ea6c495b1c3b440244f4a6dd9fe196bf2b",
        //          "coin":"usdt",
        //          "status":"2"
        //      }
        //
        //
        // fetchWithdrawals (private)
        //
        //      {
        //          "amount":2.00000000000000000000,
        //          "address":"TBjrW5JHDyPZjFc5nrRMhRWUDaJmhGhmD6",
        //          "fee":1.00000000000000000000,
        //          "networkName":"trc20",
        //          "coid":"usdt",
        //          "transferType":"数字资产提现",
        //          "txId":"47eeee2763ad49b8817524dacfa7d092fb58f8b0ab7e5d25473314df1a793c3d",
        //          "id":1902194,
        //          "applyTime":1649014002000,
        //          "status":"4"
        //      }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(transaction, "id");
        Object type = null;
        if (Helpers.isTrue(Helpers.isEqual(id, null)))
        {
            type = "deposit";
        } else
        {
            type = "withdrawal";
        }
        Object txid = this.safeString(transaction, "txId");
        Object timestamp = this.safeInteger2(transaction, "insertTime", "applyTime");
        Object address = this.safeString(transaction, "address");
        Object addressFrom = null;
        Object addressTo = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "deposit")))
        {
            addressFrom = address;
        } else
        {
            addressTo = address;
        }
        Object amount = this.safeNumber(transaction, "amount");
        Object currencyId = this.safeString2(transaction, "coin", "coid");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"), type);
        Object fee = null;
        Object feeCost = this.safeNumber(transaction, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        final Object finalId = id;
        final Object finalAddressTo = addressTo;
        final Object finalAddressFrom = addressFrom;
        final Object finalType = type;
        final Object finalStatus = status;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", finalId );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", LbankCore.this.iso8601(timestamp) );
            put( "network", LbankCore.this.networkIdToCode(LbankCore.this.safeString(transaction, "networkName"), code) );
            put( "address", address );
            put( "addressTo", finalAddressTo );
            put( "addressFrom", finalAddressFrom );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", finalStatus );
            put( "updated", null );
            put( "comment", null );
            put( "internal", (Helpers.isEqual(finalStatus, "transfer")) );
            put( "fee", finalFee );
        }};
    }

